1	//! Slice-2.4 userland bootstrap: minimal TTBR0 setup + two EL0 stub tasks.
2	//!
3	//! Builds a single 4-level page-table walk in static `.bss` storage that
4	//! maps four user pages, two per stub task:
5	//!   - `USER_CODE_VA_A` / `USER_CODE_VA_B` → a single shared kernel-owned
6	//!     page filled with the EL0 stub instructions
7	//!     (`_user_stub_start..._user_stub_end`). RO + EL0 X.
8	//!   - `USER_STACK_VA_A` / `USER_STACK_VA_B` → two kernel-owned pages used
9	//!     as each stub's EL0 stack. RW + EL0, no execute.
10	//!
11	//! Both stubs share the same code blob — they are distinguishable only by
12	//! `Proc::name` (the clock tick handler prints `name[0]` per tick to
13	//! produce the interleaved A/B output that demonstrates preemption).
14	//!
15	//! After populating each stub's process slot, the bootstrap enqueues both
16	//! into the priority-banded run queue (`proc::sched::enqueue`). The caller
17	//! (`kmain`) then transfers control to the scheduler via `proc::sched::run`.
18	//!
19	//! Phase 3's VM server replaces this entire file with proper per-process
20	//! address spaces, ELF loading, and copy-on-write semantics.
21	
22	use core::cell::UnsafeCell;
23	use core::sync::atomic::Ordering;
24	
25	use minix4_kernel_shared::ProcNr;
26	use minix4_kernel_shared::com::boot_endpoint;
27	
28	use crate::arch::aarch64::limine::kernel_va_to_pa;
29	use crate::arch::aarch64::mmu::{
30	    self, ATTR_IDX_NORMAL, PAGE_SIZE, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
31	    PTE_SH_INNER, PTE_UXN, PageTable, pte_attr_idx,
32	};
33	use crate::proc::Proc;
34	use crate::proc::sched;
35	use crate::proc::table::proc_slot_mut;
36	
37	// ----- EL0 virtual addresses ------------------------------------------------
38	
39	/// VA at which stub A's code page is mapped.
40	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
41	/// VA at which stub A's stack page is mapped.
42	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
43	
44	/// VA at which stub B's code page is mapped (one 4 KiB page above A).
45	/// Same 2 MiB L2 slot as A, so the L3_CODE table is shared.
46	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
47	/// VA at which stub B's stack page is mapped. Same 2 MiB L2 slot as A's
48	/// stack, so the L3_STACK table is shared.
49	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
50	
51	/// First proc-table slot beyond the boot image — `ProcNr(11)`. Boot procs
52	/// occupy `0..=INIT_PROC_NR` (i.e. `0..=10`).
53	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
54	/// Second stub slot, just after A.
55	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
56	
57	// SPSR_EL1 to install on each stub's `eret`. Compared to slice 2.3's
58	// `0x3C0` (all four DAIF bits masked), we clear bit 7 (`I`) so that IRQs
59	// are unmasked at EL0 — that's the whole point of slice 2.4. Bits set:
60	//   - bit 9 (D) = 1     // debug mask
61	//   - bit 8 (A) = 1     // SError mask
62	//   - bit 7 (I) = 0     // IRQs ENABLED at EL0
63	//   - bit 6 (F) = 1     // FIQ mask (we don't handle FIQ in slice 2.4)
64	//   - bits 3:0 (M)     = 0 // EL0t
65	const STUB_SPSR_EL0: u64 = 0x340;
66	
67	// ----- Static storage ------------------------------------------------------
68	
69	/// 4 KiB-aligned raw byte page, used for the EL0 stubs' code and stacks.
70	#[repr(C, align(4096))]
71	struct UserPage(UnsafeCell<[u8; PAGE_SIZE]>);
72	// SAFETY: single-threaded boot context; no concurrent access. Same invariant
73	// documented on `ProcStorage` / `PrivStorage` in `proc::table`.
74	unsafe impl Sync for UserPage {}
75	
76	impl UserPage {
77	    const EMPTY: Self = Self(UnsafeCell::new([0; PAGE_SIZE]));
78	}
79	
80	#[repr(transparent)]
81	struct PtSlot(UnsafeCell<PageTable>);
82	// SAFETY: single-threaded boot; mutation is confined to `userland_bootstrap`.
83	unsafe impl Sync for PtSlot {}
84	
85	static L0_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
86	static L1_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
87	static L2_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
88	static L3_CODE_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
89	static L3_STACK_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
90	
91	/// Single shared code page — both stubs execute the same instructions.
92	static USER_CODE_PAGE: UserPage = UserPage::EMPTY;
93	/// Per-task stack pages.
94	static USER_STACK_PAGE_A: UserPage = UserPage::EMPTY;
95	static USER_STACK_PAGE_B: UserPage = UserPage::EMPTY;
96	
97	// ----- EL0 stub blob (linked into the kernel image by `user_stub.S`) -------
98	
99	unsafe extern "C" {
100	    static _user_stub_start: u8;
101	    static _user_stub_end: u8;
102	}
103	
104	// ----- Bootstrap ----------------------------------------------------------
105	
106	/// Wire up TTBR0 mappings, copy the EL0 stub into its shared code page,
107	/// populate both stub proc slots, and enqueue them on the run queue.
108	///
109	/// SAFETY: must be called exactly once from `kmain` before any EL0 code
110	/// runs. Single-threaded boot context; no other reference into the static
111	/// page-table arena, user pages, or `PROC_TABLE[STUB_*_PROC_NR]` may exist
112	/// concurrently.
113	pub unsafe fn userland_bootstrap() {
114	    // 1. Verify Limine left MAIR_EL1's index 0 as Normal WB and that
115	    //    TCR_EL1's TTBR0-side fields match what `activate_user_ttbr0`
116	    //    expects.
117	    mmu::assert_mair_normal_wb();
118	    mmu::assert_tcr_el1_ttbr0_ready();
119	
120	    // 2. Resolve physical addresses for our static storage.
121	    let l0_pa = kernel_pa_of(L0_TABLE.0.get() as u64);
122	    let l1_pa = kernel_pa_of(L1_TABLE.0.get() as u64);
123	    let l2_pa = kernel_pa_of(L2_TABLE.0.get() as u64);
124	    let l3_code_pa = kernel_pa_of(L3_CODE_TABLE.0.get() as u64);
125	    let l3_stack_pa = kernel_pa_of(L3_STACK_TABLE.0.get() as u64);
126	    let code_page_pa = kernel_pa_of(USER_CODE_PAGE.0.get() as u64);
127	    let stack_a_pa = kernel_pa_of(USER_STACK_PAGE_A.0.get() as u64);
128	    let stack_b_pa = kernel_pa_of(USER_STACK_PAGE_B.0.get() as u64);
129	
130	    // 3. Build the user mappings. Both code VAs share the same physical
131	    //    code page; stacks are per-task. The four VAs split into two L2
132	    //    slots (one for the 0x40_xxxx code pair, one for the 0x80_xxxx
133	    //    stack pair), each backed by a single L3 table.
134	    let code_attrs =
135	        PTE_AF | PTE_SH_INNER | PTE_AP_RO_EL0 | PTE_PXN | pte_attr_idx(ATTR_IDX_NORMAL);
136	    let stack_attrs = PTE_AF
137	        | PTE_SH_INNER
138	        | PTE_AP_RW_EL0
139	        | PTE_PXN
140	        | PTE_UXN
141	        | pte_attr_idx(ATTR_IDX_NORMAL);
142	
143	    // SAFETY: single-threaded boot; no other references into the table
144	    // storage exist. PAs were resolved above.
145	    unsafe {
146	        let l0 = &mut *L0_TABLE.0.get();
147	        let l1 = &mut *L1_TABLE.0.get();
148	        let l2 = &mut *L2_TABLE.0.get();
149	        let l3_code = &mut *L3_CODE_TABLE.0.get();
150	        let l3_stack = &mut *L3_STACK_TABLE.0.get();
151	
152	        mmu::map_4k(
153	            l0, l1, l2, l3_code,
154	            l1_pa, l2_pa, l3_code_pa,
155	            USER_CODE_VA_A, code_page_pa, code_attrs,
156	        );
157	        mmu::map_4k(
158	            l0, l1, l2, l3_code,
159	            l1_pa, l2_pa, l3_code_pa,
160	            USER_CODE_VA_B, code_page_pa, code_attrs,
161	        );
162	        mmu::map_4k(
163	            l0, l1, l2, l3_stack,
164	            l1_pa, l2_pa, l3_stack_pa,
165	            USER_STACK_VA_A, stack_a_pa, stack_attrs,
166	        );
167	        mmu::map_4k(
168	            l0, l1, l2, l3_stack,
169	            l1_pa, l2_pa, l3_stack_pa,
170	            USER_STACK_VA_B, stack_b_pa, stack_attrs,
171	        );
172	    }
173	
174	    // 4. Copy the EL0 stub into its (shared) code page; clean+invalidate
175	    //    so the upcoming EL0 fetches see the new bytes.
176	    // SAFETY: `_user_stub_*` are rodata symbols inside the kernel image;
177	    // start ≤ end is enforced by the linker output of user_stub.S.
178	    let stub_len = unsafe {
179	        (&_user_stub_end as *const u8).offset_from(&_user_stub_start as *const u8) as usize
180	    };
181	    assert!(stub_len > 0 && stub_len <= PAGE_SIZE);
182	    // SAFETY: USER_CODE_PAGE is a 4 KiB-aligned BSS page; we hold the only
183	    // mutable reference (single-threaded boot).
184	    unsafe {
185	        let dst = USER_CODE_PAGE.0.get() as *mut u8;
186	        core::ptr::copy_nonoverlapping(&_user_stub_start as *const u8, dst, stub_len);
187	        mmu::flush_icache_range(USER_CODE_PAGE.0.get() as u64, stub_len);
188	    }
189	
190	    // 5. Install TTBR0 with our L0 root.
191	    // SAFETY: DAIF is still masked from boot.
192	    unsafe { mmu::activate_user_ttbr0(l0_pa) };
193	
194	    // 6. Populate each stub's proc slot. Borrows are sequential, never
195	    //    overlapping. We rely on `proc::init` (slice 2.2) having left
196	    //    slots 11 and 12 in the RTS_SLOT_FREE state.
197	    // SAFETY: single-threaded boot; sequential mutable borrows.
198	    unsafe {
199	        let pa = proc_slot_mut(STUB_A_PROC_NR).expect("STUB_A_PROC_NR within table");
200	        populate_stub_slot(
201	            pa,
202	            STUB_A_PROC_NR,
203	            b'A',
204	            USER_CODE_VA_A,
205	            USER_STACK_VA_A + PAGE_SIZE as u64,
206	        );
207	    }
208	    // SAFETY: same — A's borrow has been dropped before we take B.
209	    unsafe {
210	        let pb = proc_slot_mut(STUB_B_PROC_NR).expect("STUB_B_PROC_NR within table");
211	        populate_stub_slot(
212	            pb,
213	            STUB_B_PROC_NR,
214	            b'B',
215	            USER_CODE_VA_B,
216	            USER_STACK_VA_B + PAGE_SIZE as u64,
217	        );
218	    }
219	
220	    // 7. Enqueue both on the scheduler. They run in FIFO order within the
221	    //    same priority band (SRV_Q); the timer will preempt A after one
222	    //    quantum and B will get its first slice.
223	    // SAFETY: single-threaded boot; sched module's invariants documented
224	    // on `enqueue`. No other PROC_TABLE / RUNQ borrows live.
225	    unsafe {
226	        sched::enqueue(STUB_A_PROC_NR);
227	        sched::enqueue(STUB_B_PROC_NR);
228	    }
229	}
230	
231	fn populate_stub_slot(p: &mut Proc, nr: ProcNr, id: u8, entry_va: u64, stack_top: u64) {
232	    // Name: `id` followed by "stub\0..." padding. Lets the clock tick
233	    // handler print `name[0]` to identify which stub is running, while
234	    // `dump_tables` shows a recognizable per-stub string.
235	    p.name = [0; 16];
236	    p.name[0] = id;
237	    p.name[1] = b'-';
238	    p.name[2] = b's';
239	    p.name[3] = b't';
240	    p.name[4] = b'u';
241	    p.name[5] = b'b';
242	
243	    p.nr = nr;
244	    p.endpoint = boot_endpoint(nr);
245	    p.priv_id = None; // No Priv slot — trap-mask enforcement is slice 2.5.
246	    p.priority = crate::proc::table::SRV_Q;
247	    // 5 ticks per quantum = 50 ms at 100 Hz. Short enough to see frequent
248	    // A/B switches in the boot demo, long enough that the do_ipc log lines
249	    // (one per SVC) still get a few in per burst.
250	    p.quantum_ms = 5;
251	    p.quantum_left = p.quantum_ms as u64;
252	
253	    // EL0 entry state.
254	    p.regs.elr_el1 = entry_va;
255	    p.regs.sp_el0 = stack_top;
256	    p.regs.spsr_el1 = STUB_SPSR_EL0;
257	
258	    // Run-queue link starts cleared — `sched::enqueue` will set it.
259	    p.next_ready = None;
260	
261	    // Mark runnable.
262	    p.rts_flags.store(0, Ordering::Relaxed);
263	}
264	
265	/// Translate a kernel-image VA to PA via Limine's kernel-address response.
266	fn kernel_pa_of(va: u64) -> u64 {
267	    kernel_va_to_pa(va).expect(
268	        "Limine did not populate the kernel-address response — bootloader too old?",
269	    )
270	}
