### `kernel/src/arch/aarch64/user_stub.S` (full replacement)

```
/*
 * EL0 stubs for slice 2.5 ping-pong demo.
 *
 * Stub A is the sender: SENDREC to B, echoes the m_type back from the
 * reply into a counter register, loops. Stub B is the echo server: RECEIVE
 * from ANY, mirror m_type back to m_source with SEND, loop.
 *
 * Both stubs are PC-relative-free; the same bytes work at any VA. Each
 * stub has its own Message buffer carved out of its EL0 stack page (the
 * stack VA is baked in as a mov immediate — see USER_STACK_VA_{A,B} in
 * userland.rs). Buffer layout per task:
 *   [stack_top - 104, stack_top)  → Message scratch
 *   SP_EL0 starts at stack_top - 128 (16-byte aligned headroom)
 *
 * Argument convention from kernel-shared/src/ipc_const.rs:
 *   x0 = src_dst endpoint, x1 = call_nr, x2 = &Message
 *
 * Per docs/ipc.md:319-323 the aarch64 SVC ABI is (x0, x1, x2, x3). Slice
 * 2.5 keeps the slice-2.3 mapping that do_ipc reads: frame.x[0]=src_dst,
 * frame.x[1]=call_nr, frame.x[2]=msg_addr.
 */

    .equ SEND,     1
    .equ RECEIVE,  2
    .equ SENDREC,  3
    .equ ANY,      0x7FFF              // endpoint_proc 0x7FFF == ENDPOINT_SLOT_TOP at gen 0
    .equ ENDPOINT_A, 11                 // boot_endpoint(ProcNr(11))
    .equ ENDPOINT_B, 12                 // boot_endpoint(ProcNr(12))
    .equ MSG_OFF,  104                  // size of Message; subtract from SP_EL0 to get buf addr

/* ---- Stub A: sender ----------------------------------------------------- */

    .section .rodata.user_stub_a, "a", %progbits
    .balign 4
    .global _user_stub_a_start
_user_stub_a_start:
    // x19 = persistent counter (callee-saved by AAPCS — survives SVC since
    // the kernel save/restore preserves x19 as part of the full frame).
    mov     x19, #0
1:
    // Build a Message at [SP_EL0 - 104, SP_EL0). SP stays 16-byte aligned.
    sub     x9, sp, #MSG_OFF
    str     wzr, [x9, #0]               // m_source = 0 (kernel overwrites)
    str     w19, [x9, #4]               // m_type   = counter
    // payload left uninitialized (uninspected by B in slice 2.5).

    mov     x0, #ENDPOINT_B
    mov     x1, #SENDREC
    mov     x2, x9
    svc     #0
    // On return: deliver_msg has landed at [x9, x9+104). Bump counter.
    add     x19, x19, #1
    b       1b
    .global _user_stub_a_end
_user_stub_a_end:
    .size   _user_stub_a_start, _user_stub_a_end - _user_stub_a_start

/* ---- Stub B: echo server ------------------------------------------------ */

    .section .rodata.user_stub_b, "a", %progbits
    .balign 4
    .global _user_stub_b_start
_user_stub_b_start:
1:
    sub     x9, sp, #MSG_OFF
    mov     x0, #ANY
    mov     x1, #RECEIVE
    mov     x2, x9
    svc     #0
    // Read m_source out of the delivered message; reply to it with SEND
    // carrying the same m_type (mirror).
    ldr     w10, [x9, #0]               // m_source
    // m_type already in [x9 + 4]; leave it.
    sxtw    x10, w10
    mov     x0, x10
    mov     x1, #SEND
    mov     x2, x9
    svc     #0
    b       1b
    .global _user_stub_b_end
_user_stub_b_end:
    .size   _user_stub_b_start, _user_stub_b_end - _user_stub_b_start
```

