## 8. Privilege setup for the two stubs

New `kernel/src/proc/priv.rs` (or co-locate in `proc/table.rs`):

```rust
const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
const STUB_B_PRIV_ID: PrivId = PrivId::new(17);

/// Install priv slots for the two slice-2.5 ping-pong stubs. Must run
/// after `proc::init` (so `IMAGE` slots 0..16 are filled) and before
/// `sched::enqueue` (so the IPC path sees the priv_id when the stubs
/// first SVC).
pub unsafe fn install_stub_privs(a_nr: ProcNr, b_nr: ProcNr) {
    install_one(STUB_A_PRIV_ID, a_nr, STUB_B_PRIV_ID);
    install_one(STUB_B_PRIV_ID, b_nr, STUB_A_PRIV_ID);
}

unsafe fn install_one(id: PrivId, owner: ProcNr, peer: PrivId) {
    // SAFETY: priv slot in range; single-threaded boot context.
    let pr = unsafe { priv_slot_mut(id).expect("priv slot in range") };
    pr.id           = id;
    pr.proc_nr      = Some(owner);
    pr.flags        = SYS_PROC | BILLABLE | PREEMPTIBLE;
    pr.trap_mask    = SRV_T;   // SEND, RECEIVE, SENDREC, NOTIFY, SENDNB, SENDA all allowed
    pr.sig_mgr      = boot_endpoint(RS_PROC_NR);  // unused in 2.5 but harmless
    pr.notify_pending.fill(0);
    pr.asyn_pending.fill(0);

    // ipc_to: A may send to B only; B may send to A only. Bit `peer.get()`.
    pr.ipc_to.fill(0);
    let b = peer.get() as usize;
    pr.ipc_to[b / 32] |= 1 << (b % 32);

    // k_call_mask: no kernel calls in slice 2.5 (kernel-call dispatch
    // arrives slice 2.6). Leave zeroed.
    pr.k_call_mask.fill(0);
}
```

