61	// ---------------------------------------------------------------------------
62	// Current-proc accessors.
63	// ---------------------------------------------------------------------------
64	
65	/// Borrow the currently-running process's slot.
66	///
67	/// SAFETY: caller must respect the single-threaded-boot invariant on
68	/// `PROC_TABLE`. The returned `&'static mut Proc` must not alias any other
69	/// reference into the table.
70	pub unsafe fn current_proc_mut() -> Option<&'static mut Proc> {
71	    let n = CURRENT_PROC_NR.load(Ordering::Relaxed);
72	    if n == NO_PROC {
73	        return None;
74	    }
75	    // SAFETY: forwarded — caller holds the no-aliasing invariant.
