89	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
90	pub unsafe fn enqueue(nr: ProcNr) {
91	    let prio = unsafe {
92	        let p = proc_slot_mut(nr).expect("enqueue: nr out of range");
93	        assert!(p.next_ready.is_none(), "enqueue: process already queued");
