169	/// higher priority, so we scan `0..NR_SCHED_QUEUES` and return the first
170	/// non-empty head.
171	pub fn pick_proc() -> Option<ProcNr> {
172	    // SAFETY: read-only snapshot under the single-threaded invariant.
173	    let runq = unsafe { &*RUNQ.0.get() };
174	    runq.head.iter().find_map(|&h| h)
175	}
176	
177	// ---------------------------------------------------------------------------
178	// Dispatch helpers.
179	// ---------------------------------------------------------------------------
180	
181	unsafe extern "C" {
182	    /// Restores `tpidr_el1`-pointed `ArchRegisterFrame` and erets into EL0.
183	    /// Defined in `kernel/src/arch/aarch64/trap.S`.
184	    fn el1_return_to_user() -> !;
185	}
