187	/// Park `&mut p.regs` in `TPIDR_EL1` so the SVC/IRQ entry paths and
188	/// `el1_return_to_user` can locate the current process's register frame.
189	///
190	/// SAFETY: `p` must be the slot whose number is currently parked in
191	/// `CURRENT_PROC_NR`. Caller must hold the single-threaded invariant.
192	unsafe fn set_tpidr_to(p: &mut Proc) {
193	    let regs_ptr: *mut ArchRegisterFrame = &mut p.regs;
194	    // SAFETY: TPIDR_EL1 is EL1-only and used only by our own SVC + IRQ stubs
195	    // and `el1_return_to_user`. No other code reads or writes it.
196	    unsafe {
197	        core::arch::asm!(
