199	            "isb",
200	            in(reg) regs_ptr,
201	            options(nomem, nostack, preserves_flags),
202	        );
203	    }
204	}
205	
206	/// First entry into EL0 from `kmain`.
207	///
208	/// Pre-condition: the desired-to-run procs have already been [`enqueue`]d.
209	/// Picks the highest-priority head, parks its frame in `TPIDR_EL1`, and
210	/// jumps to the assembly restore-and-`eret` stub. Never returns.
211	///
212	/// SAFETY: at least one process must be enqueued (otherwise we'd `panic` in
213	/// EL1 with the boot stack still active). The picked process's `regs` must
214	/// be fully initialized — see `userland_bootstrap`. Must be called with
215	/// DAIF (I) still masked at EL1; the per-proc SPSR carries the EL0 mask
216	/// state that takes effect on `eret`.
217	pub unsafe fn run() -> ! {
218	    let first_nr = pick_proc().expect("run: empty run queue");
219	    CURRENT_PROC_NR.store(first_nr.get(), Ordering::Relaxed);
220	    // SAFETY: single-threaded boot; we hold the only reference into the
221	    // first proc's slot.
222	    let first = unsafe { proc_slot_mut(first_nr).expect("run: nr out of range") };
223	    // SAFETY: same — exclusive borrow above.
224	    unsafe { set_tpidr_to(first) };
225	    // SAFETY: trap.S contract documented at `el1_return_to_user`.
226	    unsafe { el1_return_to_user() }
227	}
228	
229	/// Quantum-exhaust path: re-enqueue the current proc at the tail of its
230	/// priority band, pick the next runnable, and update `TPIDR_EL1`.
231	///
232	/// Called from `clock::tick` when the running proc's `quantum_left` hits
233	/// zero. The IRQ stub's trailing `bl el1_return_to_user` reads the
234	/// (possibly new) `TPIDR_EL1` and restores that frame, so the context
235	/// switch happens transparently.
236	///
237	/// If `pick_proc` somehow finds no runnable proc (we just re-enqueued
238	/// current, so it should always find at least that one), we leave
239	/// `TPIDR_EL1` alone and stay on the current proc.
240	///
241	/// SAFETY: caller holds the single-threaded invariant; called only from
242	/// IRQ context with no other PROC_TABLE / RUNQ borrows live.
243	pub unsafe fn reschedule() {
244	    let cur_raw = CURRENT_PROC_NR.load(Ordering::Relaxed);
245	    if cur_raw != NO_PROC {
246	        let cur_nr = ProcNr::new(cur_raw);
247	        // Refill quantum and clear the quantum-exhaust flag *before*
248	        // re-enqueuing, so the re-enqueued process is in the runnable state.
249	        // SAFETY: single-threaded; cur_nr came from CURRENT_PROC_NR.
250	        unsafe {
251	            let cur = proc_slot_mut(cur_nr).expect("reschedule: current out of range");
252	            cur.quantum_left = cur.quantum_ms as u64;
253	            cur.rts_flags.fetch_and(!RTS_NO_QUANTUM, Ordering::Relaxed);
254	        }
255	        // SAFETY: cur_nr borrow above has been dropped.
256	        unsafe {
257	            dequeue(cur_nr);
258	            enqueue(cur_nr);
259	        }
260	    }
261	
262	    let next_nr = match pick_proc() {
263	        Some(nr) => nr,
264	        None => return, // No runnable procs — stay on current.
265	    };
266	    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);
267	    // SAFETY: next_nr is in range (came from a queue we just maintained).
268	    let next = unsafe { proc_slot_mut(next_nr).expect("reschedule: next out of range") };
269	    // SAFETY: exclusive borrow above.
270	    unsafe { set_tpidr_to(next) };
271	}
