//! Static process and privilege tables, plus the boot-image table that
//! drives initial population.
//!
//! Storage uses `UnsafeCell<[T; N]>` wrapped in a `Sync` newtype: slice 2.2
//! runs on one CPU with interrupts masked, so a `Mutex` would buy nothing
//! over `unsafe` accessors that document the single-threaded invariant.
//! Slice 2.4 (timer + preemption) will revisit this — at that point we'll
//! need a per-table lock or a percpu pattern, not before.

use core::cell::UnsafeCell;

use minix4_kernel_shared::callnr::NR_KERN_CALLS_PHASE2;
use minix4_kernel_shared::com::{
    ASYNCM, CLOCK, DS_PROC_NR, HARDWARE, IDLE, INIT_PROC_NR, MEM_PROC_NR, MFS_PROC_NR,
    NR_BOOT_PROCS, NR_PROCS, NR_SYS_PROCS, NR_TASKS, PFS_PROC_NR, PM_PROC_NR, RS_PROC_NR,
    SCHED_PROC_NR, SYSTEM, TTY_PROC_NR, VFS_PROC_NR, VM_PROC_NR, boot_endpoint,
};
use minix4_kernel_shared::{PrivId, ProcNr};

use super::flags::{
    BILLABLE, CSK_T, PREEMPTIBLE, ROOT_SYS_PROC, RTS_NO_PRIV, SRV_T, SYS_PROC, TSK_T,
    VM_SYS_PROC,
};
use super::priv_struct::{IPC_MAP_CHUNKS, K_CALL_MASK_CHUNKS, Priv};
use super::proc_struct::{PROC_NAME_LEN, Proc};

/// Total slots in the process table: kernel tasks plus user-process room.
pub const N_PROC_SLOTS: usize = NR_TASKS + NR_PROCS;

// ---------------------------------------------------------------------------
// Scheduling constants (slice 2.4 expands these into full bands).
// ---------------------------------------------------------------------------

/// Highest scheduler priority — reserved for kernel tasks.
pub const TASK_Q: u8 = 0;
/// Default priority for the root system process (RS).
pub const RS_Q: u8 = 4;
/// Default priority for the VM server.
pub const VM_Q: u8 = 4;
/// Default priority for ordinary boot servers.
pub const SRV_Q: u8 = 8;
/// Default priority for `init`.
pub const INIT_Q: u8 = 8;
/// Lowest priority — the idle task only.
pub const IDLE_Q: u8 = 15;

/// Default scheduling quantum for user-class servers (ms).
pub const SRV_QUANTUM_MS: u32 = 200;

// ---------------------------------------------------------------------------
// Static storage.
// ---------------------------------------------------------------------------

#[repr(transparent)]
struct ProcStorage(UnsafeCell<[Proc; N_PROC_SLOTS]>);
// SAFETY: slice 2.2 runs single-threaded with interrupts masked; concurrent
// access to PROC_TABLE is impossible. Future slices that enable preemption
// must wrap this in a proper lock before keeping this `unsafe impl`.
unsafe impl Sync for ProcStorage {}

#[repr(transparent)]
struct PrivStorage(UnsafeCell<[Priv; NR_SYS_PROCS]>);
// SAFETY: same single-threaded invariant as ProcStorage.
unsafe impl Sync for PrivStorage {}

static PROC_TABLE: ProcStorage = ProcStorage(UnsafeCell::new(
    [const { Proc::EMPTY }; N_PROC_SLOTS],
));
static PRIV_TABLE: PrivStorage = PrivStorage(UnsafeCell::new(
    [const { Priv::EMPTY }; NR_SYS_PROCS],
));

/// Map a [`ProcNr`] to its index in the process table.
///
/// Kernel tasks (negative `nr`) land in slots `[0, NR_TASKS)`; user processes
/// land in `[NR_TASKS, N_PROC_SLOTS)`. Returns `None` if `nr` is outside the
/// allocated range.
pub const fn proc_index(nr: ProcNr) -> Option<usize> {
    let n = nr.get();
    let shifted = n + NR_TASKS as i32;
    if shifted < 0 || (shifted as usize) >= N_PROC_SLOTS {
        None
    } else {
        Some(shifted as usize)
    }
}

/// Map a [`PrivId`] to its index in the privilege table.
pub const fn priv_index(id: PrivId) -> Option<usize> {
    let n = id.as_usize();
    if n >= NR_SYS_PROCS { None } else { Some(n) }
}

// ---------------------------------------------------------------------------
// Boot image.
// ---------------------------------------------------------------------------

struct BootEntry {
    nr: ProcNr,
    name: &'static [u8],
    priv_flags: u16,
    trap_mask: u16,
    priority: u8,
    quantum_ms: u32,
    runnable: bool,
}

const N_IMAGE: usize = NR_TASKS + NR_BOOT_PROCS;
const _: () = assert!(N_IMAGE == 16);

static IMAGE: [BootEntry; N_IMAGE] = [
    // --- Kernel tasks (always runnable) -----------------------------------
    BootEntry { nr: ASYNCM,   name: b"asyncm",   priv_flags: SYS_PROC,            trap_mask: TSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
    BootEntry { nr: IDLE,     name: b"idle",     priv_flags: SYS_PROC | BILLABLE, trap_mask: TSK_T, priority: IDLE_Q, quantum_ms: 0, runnable: true },
    BootEntry { nr: CLOCK,    name: b"clock",    priv_flags: SYS_PROC,            trap_mask: CSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
    BootEntry { nr: SYSTEM,   name: b"system",   priv_flags: SYS_PROC,            trap_mask: CSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
    BootEntry { nr: HARDWARE, name: b"hardware", priv_flags: SYS_PROC,            trap_mask: TSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },

    // --- Boot servers (blocked on RTS_NO_PRIV until slice 2.6 loads ELFs) -
    BootEntry { nr: PM_PROC_NR,    name: b"pm",    priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: VFS_PROC_NR,   name: b"vfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: RS_PROC_NR,    name: b"rs",    priv_flags: SYS_PROC | PREEMPTIBLE | ROOT_SYS_PROC, trap_mask: SRV_T, priority: RS_Q,   quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: MEM_PROC_NR,   name: b"memory",priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: TTY_PROC_NR,   name: b"tty",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: DS_PROC_NR,    name: b"ds",    priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: MFS_PROC_NR,   name: b"mfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: VM_PROC_NR,    name: b"vm",    priv_flags: SYS_PROC | PREEMPTIBLE | VM_SYS_PROC,   trap_mask: SRV_T, priority: VM_Q,   quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: PFS_PROC_NR,   name: b"pfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: SCHED_PROC_NR, name: b"sched", priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
    BootEntry { nr: INIT_PROC_NR,  name: b"init",  priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: INIT_Q, quantum_ms: SRV_QUANTUM_MS, runnable: false },
];

// ---------------------------------------------------------------------------
// Access helpers. All return raw pointers — callers carry the single-threaded
// invariant.
// ---------------------------------------------------------------------------

/// SAFETY: caller must ensure no other reference into `PROC_TABLE` exists.
pub(crate) unsafe fn proc_slot_mut(nr: ProcNr) -> Option<&'static mut Proc> {
    let idx = proc_index(nr)?;
    // SAFETY: `idx` is in-range; single-threaded boot context.
    let arr = unsafe { &mut *PROC_TABLE.0.get() };
    Some(&mut arr[idx])
}

/// SAFETY: caller must ensure no exclusive reference into `PROC_TABLE` exists.
pub(crate) unsafe fn proc_table_ref() -> &'static [Proc; N_PROC_SLOTS] {
    // SAFETY: single-threaded boot context.
    unsafe { &*PROC_TABLE.0.get() }
}

/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
    let idx = priv_index(id)?;
    // SAFETY: `idx` is in-range; single-threaded boot context.
    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
    Some(&mut arr[idx])
}

/// SAFETY: caller must ensure no exclusive reference into `PRIV_TABLE` exists.
pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
    // SAFETY: single-threaded boot context.
    unsafe { &*PRIV_TABLE.0.get() }
}

// ---------------------------------------------------------------------------
// Boot-time population.
// ---------------------------------------------------------------------------

/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
///
/// Called exactly once from `kmain` during boot. Slice 2.4's scheduler will
/// assume one-shot init; double-calling would clobber any RTS bits the
/// scheduler has set since.
pub fn init() {
    init_empty_slots();
    init_boot_image();
}

fn init_empty_slots() {
    // Give every slot a valid (nr, endpoint) so that index-based traversal
    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
    for i in 0..N_PROC_SLOTS {
        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
        // SAFETY: index in-range; single-threaded boot context; no other
        // references into PROC_TABLE exist at this point in `init`.
        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
        p.nr = nr;
        p.endpoint = boot_endpoint(nr);
        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
    }

    for i in 0..NR_SYS_PROCS {
        // SAFETY: index in-range; single-threaded boot context.
        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }
            .expect("priv index in range");
        pr.id = PrivId::new(i as u16);
    }
}

fn init_boot_image() {
    // Active priv-slot count after population — the IPC bitmap for SRV_T
    // entries needs to enumerate every active slot.
    let n_active = N_IMAGE as u16;

    for (slot, entry) in IMAGE.iter().enumerate() {
        let priv_id = PrivId::new(slot as u16);
        populate_priv(priv_id, entry, n_active);
        populate_proc(priv_id, entry);
    }
}

fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
    // overlapping reference into PRIV_TABLE held across the call.
    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
    pr.id = id;
    pr.proc_nr = Some(entry.nr);
    pr.flags = entry.priv_flags;
    pr.trap_mask = entry.trap_mask;

    if entry.trap_mask == SRV_T {
        // SRV_T privs can send to every active slot. Set bits [0, n_active).
        fill_bits(&mut pr.ipc_to, n_active as usize);
        // SRV_T privs can issue every kernel call defined so far.
        // TODO(slice 2.6): widen as new kernel calls land — this bound must
        // track the highest `SYS_*` number, not the Phase-2 count.
        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE2);
    }
    // Kernel-task slots leave ipc_to and k_call_mask zeroed.

    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
    pr.notify_pending.fill(0);
    pr.asyn_pending.fill(0);
}

fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
    // SAFETY: proc index in-range; single-threaded boot context; no
    // overlapping reference into PROC_TABLE held across the call.
    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
    p.priv_id = Some(priv_id);
    p.priority = entry.priority;
    p.quantum_ms = entry.quantum_ms;
    p.quantum_left = entry.quantum_ms as u64;
    p.endpoint = boot_endpoint(entry.nr);
    p.nr = entry.nr;

    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
    p.name[..n].copy_from_slice(&entry.name[..n]);
    p.name[n..].fill(0);

    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
    p.rts_flags
        .store(rts, core::sync::atomic::Ordering::Relaxed);
}

/// Set the lowest `n` bits in a `u32` bitmap.
fn fill_bits(map: &mut [u32], n: usize) {
    for i in 0..n {
        let word = i / 32;
        let bit = i % 32;
        if word < map.len() {
            map[word] |= 1 << bit;
        }
    }
}

// Compile-time sanity that the bitmap sizing came out as expected.
const _: () = assert!(IPC_MAP_CHUNKS == 2);
const _: () = assert!(K_CALL_MASK_CHUNKS == 1);

/// Number of slots in `PROC_TABLE` (for the dump helper).
pub const fn n_proc_slots() -> usize {
    N_PROC_SLOTS
}

/// Number of slots in `IMAGE` (for the dump helper).
pub const fn n_image_slots() -> usize {
    N_IMAGE
}

// IoRange/MemRange fields and several constants are forward declarations for
// slice 2.6 (kernel-call dispatch) — they are written by `proc::init` and read
// once slices 2.5/2.6 wire up IPC and `SYS_*` handlers.
#![allow(dead_code)]

//! Privilege-table entry.
//!
//! Mirrors MINIX 3 `kernel/priv.h`'s `struct priv` with the same simplifications
//! as [`Proc`]: no SMP, no live update, no profiling. The bitmaps are sized to
//! `NR_SYS_PROCS` (for IPC / notify / asyn target maps) and `NR_SYS_CALLS`
//! (for the kernel-call mask).
//!
//! [`Proc`]: super::Proc

use arrayvec::ArrayVec;

use minix4_kernel_shared::callnr::NR_SYS_CALLS;
use minix4_kernel_shared::com::NR_SYS_PROCS;
use minix4_kernel_shared::endpoint::{Endpoint, NONE};
use minix4_kernel_shared::sys_limits::{NR_IO_RANGE, NR_IRQ, NR_MEM_RANGE};
use minix4_kernel_shared::{PrivId, ProcNr};

/// Number of `u32` chunks needed to cover `NR_SYS_PROCS` bits.
pub const IPC_MAP_CHUNKS: usize = NR_SYS_PROCS / 32;
/// Number of `u32` chunks needed to cover `NR_SYS_CALLS` bits.
pub const K_CALL_MASK_CHUNKS: usize = NR_SYS_CALLS / 32;

const _: () = assert!(NR_SYS_PROCS % 32 == 0);

/// I/O port range a privileged process may access.
#[derive(Copy, Clone, Debug, Default)]
pub struct IoRange {
    pub base: u64,
    pub count: u64,
}

/// Physical memory range a privileged process may map.
#[derive(Copy, Clone, Debug, Default)]
pub struct MemRange {
    pub base: u64,
    pub count: u64,
}

/// One slot in the kernel's privilege table.
///
/// Each system (privileged) process owns exactly one `Priv`; user processes
/// share a single user-class slot (`USER_PRIV_ID`).
#[repr(C)]
pub struct Priv {
    /// Slot index into the privilege table.
    pub id: PrivId,
    /// Process this slot belongs to, if any.
    pub proc_nr: Option<ProcNr>,
    /// Privilege flags (`PREEMPTIBLE`, `SYS_PROC`, …).
    pub flags: u16,
    /// Trap mask — bit `i` allows IPC primitive `i`.
    pub trap_mask: u16,

    // ----- IPC target / pending bitmaps ------------------------------------
    /// Bitmap of privileged slots this process may send to.
    pub ipc_to: [u32; IPC_MAP_CHUNKS],
    /// Bitmap of allowed kernel calls.
    pub k_call_mask: [u32; K_CALL_MASK_CHUNKS],
    /// Bitmap of pending notifications.
    pub notify_pending: [u32; IPC_MAP_CHUNKS],
    /// Bitmap of pending async messages.
    pub asyn_pending: [u32; IPC_MAP_CHUNKS],

    /// Signal manager endpoint (delivers signals raised against us).
    pub sig_mgr: Endpoint,

    // ----- Resource ownership ---------------------------------------------
    pub io_ranges: ArrayVec<IoRange, NR_IO_RANGE>,
    pub mem_ranges: ArrayVec<MemRange, NR_MEM_RANGE>,
    pub irqs: ArrayVec<u32, NR_IRQ>,

    /// Address of the grant table within the owner's address space (set by
    /// `SYS_SETGRANT`); slice 2.6 starts honoring this.
    pub grant_table: u64,
    /// Number of grant-table entries.
    pub grant_entries: u32,
}

impl Priv {
    /// Empty-slot initializer used to fill the static privilege table at boot.
    pub const EMPTY: Self = Self {
        id: PrivId::new(0),
        proc_nr: None,
        flags: 0,
        trap_mask: 0,
        ipc_to: [0; IPC_MAP_CHUNKS],
        k_call_mask: [0; K_CALL_MASK_CHUNKS],
        notify_pending: [0; IPC_MAP_CHUNKS],
        asyn_pending: [0; IPC_MAP_CHUNKS],
        sig_mgr: NONE,
        io_ranges: ArrayVec::new_const(),
        mem_ranges: ArrayVec::new_const(),
        irqs: ArrayVec::new_const(),
        grant_table: 0,
        grant_entries: 0,
    };
}

//! IPC subsystem.
//!
//! Slice 2.3 ships only `do_ipc` as an observable stub — it prints the
//! caller's IPC arguments to the UART and stores `OK` in the caller's `x0`,
//! proving that the EL0 → SVC → kernel → eret round-trip works end-to-end.
//!
//! Slice 2.5 replaces this with the real IPC engine: `mini_send`,
//! `mini_receive`, `mini_notify`, the `caller_q` traversal, `MF_DELIVERMSG`
//! delivery, and trap-mask enforcement.

use core::fmt::Write;
use core::sync::atomic::{AtomicU32, Ordering};

use crate::arch::ArchRegisterFrame;
use crate::uart::Uart;

static CALL_COUNT: AtomicU32 = AtomicU32::new(0);

/// IPC dispatch.
///
/// Called from `trap.S` immediately after the SVC entry stub has saved the
/// caller's registers into `frame`. MINIX-style argument convention:
///
/// | reg | meaning                       |
/// |-----|-------------------------------|
/// | x0  | source/destination endpoint   |
/// | x1  | call number (SEND, SENDREC …) |
/// | x2  | pointer to the user's Message |
///
/// The slice-2.3 stub doesn't actually deliver a message anywhere — it just
/// logs the call and synthesizes an `OK` return value in `frame.x[0]`.
#[unsafe(no_mangle)]
pub extern "C" fn do_ipc(frame: &mut ArchRegisterFrame) {
    let src_dst = frame.x[0] as i32;
    let call_nr = frame.x[1] as i32;
    let msg_addr = frame.x[2];

    let n = CALL_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
    let mut uart = Uart::new();
    let _ = writeln!(
        uart,
        "do_ipc[{n}]: call_nr={call_nr} src_dst={src_dst} msg={msg_addr:#018x}",
    );

    // OK return code, MINIX-style. The SVC restore path puts this in the
    // caller's x0.
    frame.x[0] = 0;
}

