1	//! IPC primitive numbers — values that go in `r1`/`x16` on the IPC trap.
2	//!
3	//! Matches MINIX 3 `include/minix/ipcconst.h`. The numbering is shared
4	//! between the kernel's `do_ipc()` dispatch and the user-space stub.
5	
6	/// Blocking send. Caller blocks until the receiver accepts the message.
7	pub const SEND: i32 = 1;
8	/// Blocking receive. Caller blocks until a message arrives.
9	pub const RECEIVE: i32 = 2;
10	/// Atomic send + receive (the common case for client-server calls).
11	pub const SENDREC: i32 = 3;
12	/// Non-blocking notification — sets a bit in the receiver's notify bitmap.
13	pub const NOTIFY: i32 = 4;
14	/// Non-blocking send — returns `ENOTREADY` if the receiver is not waiting.
15	pub const SENDNB: i32 = 5;
16	/// Asynchronous send — the kernel walks the caller's async-send table.
17	pub const SENDA: i32 = 16;
18	
19	/// Kernel-info introspection trap (separate from `SYS_GETINFO`); reserved
20	/// but unused in Phase 2.
21	pub const MINIX_KERNINFO: i32 = 32;
22	
23	#[cfg(test)]
24	mod tests {
25	    use super::*;
26	
