1	//! Exception vector installation and the Phase 1 panic-on-trap handler.
2	//!
3	//! The vector table itself lives in `vectors.S` (16 ARMv8 vectors, each
4	//! saving the register file into an `ExceptionFrame` on the stack and
5	//! calling into `exception_entry` below). Phase 1 treats every exception
6	//! as fatal: we print the relevant system registers and panic. Real IRQ,
7	//! syscall, and page-fault handlers replace this in Phase 2 onward.
8	
9	use crate::arch::aarch64::uart::Pl011;
10	use core::arch::asm;
11	use core::fmt::Write;
12	
13	#[repr(C)]
14	pub struct ExceptionFrame {
15	    pub gprs: [u64; 31], // x0..x30, mirror of the stp/str sequence in vectors.S
16	    pub spsr_el1: u64,
17	    pub elr_el1: u64,
18	    pub esr_el1: u64,
19	    pub far_el1: u64,
20	    pub _pad: u64,
21	}
22	
23	// Frame layout is hand-encoded in vectors.S (sub sp, sp, #0x120 + the stp/str
24	// sequence). Catch accidental field reordering or resizing at compile time
25	// instead of as silent stack corruption on the first real exception.
26	const _: () = assert!(core::mem::size_of::<ExceptionFrame>() == 0x120);
27	
28	unsafe extern "C" {
29	    static _vector_table: u8;
30	}
31	
32	pub fn install_vectors() {
33	    let addr = core::ptr::addr_of!(_vector_table) as u64;
34	    // SAFETY: VBAR_EL1 is writable at EL1. The address points at the linker-
35	    // provided vector table symbol, aligned to 2 KiB by `.balign 0x800` in
36	    // vectors.S (required: VBAR_EL1[10:0] are RES0). The table is in .text,
37	    // never freed.
38	    unsafe {
39	        asm!(
40	            "msr vbar_el1, {0}",
41	            "isb",
42	            in(reg) addr,
43	            options(nomem, nostack),
44	        );
45	    }
46	}
47	
48	#[unsafe(no_mangle)]
49	extern "C" fn exception_entry(frame: &ExceptionFrame, kind: u64) -> ! {
50	    let mut uart = Pl011::new();
51	    let _ = writeln!(uart);
52	    let _ = writeln!(uart, "!!! kernel exception (vector index {kind})");
53	    let ec = (frame.esr_el1 >> 26) & 0x3F;
54	    let iss = frame.esr_el1 & 0xFF_FFFF;
55	    let _ = writeln!(
56	        uart,
57	        "    ESR_EL1  = {:#018x}  (EC = {:#04x}, ISS = {:#08x})",
58	        frame.esr_el1, ec, iss
59	    );
60	    let _ = writeln!(
61	        uart,
62	        "    ELR_EL1  = {:#018x}  FAR_EL1  = {:#018x}",
63	        frame.elr_el1, frame.far_el1
64	    );
65	    let _ = writeln!(uart, "    SPSR_EL1 = {:#018x}", frame.spsr_el1);
66	    panic!(
67	        "aarch64 exception: kind={kind} ESR_EL1={:#x}",
68	        frame.esr_el1
69	    );
70	}
71	
72	/// Diagnose-and-panic helper for EL0 sync exceptions that aren't `SVC`.
73	///
74	/// `trap.S` calls this from vector slot 8 when ESR_EL1.EC ≠ 0x15 (SVC64).
75	/// Slice 2.3 doesn't expect any other EL0 sync exception in the happy path,
76	/// so we treat them as fatal — same policy as slice 2.2's blanket
77	/// `exception_entry`.
78	#[unsafe(no_mangle)]
79	extern "C" fn el0_sync_unexpected(esr: u64, elr: u64, far: u64) -> ! {
80	    let mut uart = Pl011::new();
81	    let ec = (esr >> 26) & 0x3F;
82	    let iss = esr & 0xFF_FFFF;
83	    let _ = writeln!(uart);
84	    let _ = writeln!(uart, "!!! unexpected EL0 sync exception (not SVC)");
85	    let _ = writeln!(
86	        uart,
87	        "    ESR_EL1  = {esr:#018x}  (EC = {ec:#04x}, ISS = {iss:#08x})",
88	    );
89	    let _ = writeln!(uart, "    ELR_EL1  = {elr:#018x}  FAR_EL1  = {far:#018x}");
90	    panic!("EL0 sync exception: EC={ec:#x} ESR_EL1={esr:#x}");
91	}
