1	// Assembles the per-arch entry path and exception vectors into the kernel.
2	//
3	// .S files go through clang (cross-targeted at the kernel triple) and the
4	// resulting .o files are passed straight to the linker via cargo:rustc-link-arg.
5	// We deliberately *avoid* the cc crate's static-library packaging because the
6	// linker's archive member resolution wouldn't pull in `_start` (it's only
7	// referenced via the linker-script `ENTRY` directive, not from any Rust
8	// symbol). Direct .o linkage sidesteps that, and it also dodges the
9	// macOS-ar/ELF-object mismatch entirely.
10	
11	use std::path::PathBuf;
12	use std::process::Command;
13	
14	fn main() {
15	    let arch =
16	        std::env::var("CARGO_CFG_TARGET_ARCH").expect("CARGO_CFG_TARGET_ARCH unset");
17	    let out_dir = PathBuf::from(std::env::var_os("OUT_DIR").expect("OUT_DIR unset"));
18	
19	    match arch.as_str() {
20	        "aarch64" => {
21	            let sources = [
22	                "src/arch/aarch64/entry.S",
23	                "src/arch/aarch64/vectors.S",
24	                "src/arch/aarch64/trap.S",
25	                "src/arch/aarch64/interrupt.S",
26	                "src/arch/aarch64/user_stub.S",
27	            ];
28	            for src in &sources {
29	                println!("cargo:rerun-if-changed={src}");
30	                let stem = std::path::Path::new(src)
31	                    .file_stem()
32	                    .unwrap()
33	                    .to_string_lossy();
34	                let obj = out_dir.join(format!("{stem}.o"));
35	                let status = Command::new("clang")
36	                    .args([
37	                        "--target=aarch64-unknown-none",
38	                        "-ffreestanding",
39	                        "-c",
40	                        src,
41	                        "-o",
42	                    ])
43	                    .arg(&obj)
44	                    .status()
45	                    .expect("failed to spawn clang");
46	                if !status.success() {
47	                    panic!("clang failed assembling {src}");
48	                }
49	                println!("cargo:rustc-link-arg={}", obj.display());
50	            }
51	            println!("cargo:rerun-if-changed=src/arch/aarch64/linker.ld");
52	        }
53	        "x86_64" => {
54	            // Phase 8 territory -- nothing to assemble yet.
55	        }
56	        other => panic!("unsupported target arch: {other}"),
57	    }
58	}
