1	//! Minimal MMU helpers for the slice-2.3 EL0 stub task.
2	//!
3	//! Slice 2.3 needs exactly two user mappings — one code page and one stack
4	//! page — installed via TTBR0_EL1. Phase 3's VM server takes this over and
5	//! replaces it with proper per-process address spaces; for now we hand-roll
6	//! a tiny 4 KiB-granule, 4-level page-table walk in static `.bss` storage.
7	//!
8	//! Layout decisions:
9	//! - 4 KiB granule, 4 levels, T0SZ = 16 (48-bit VA). Symmetric with the
10	//!   TTBR1 settings Limine programmed for the higher-half kernel; using the
11	//!   same granule for TTBR0 lets us reuse Limine's MAIR indices unchanged.
12	//! - We never write `MAIR_EL1` — Limine has already placed `Normal WB` at
13	//!   AttrIdx 0. We read once at boot and assert that invariant.
14	//! - We touch only the `*0` field-set bits of `TCR_EL1` (T0SZ / IRGN0 /
15	//!   ORGN0 / SH0 / TG0 / EPD0) — the `*1` fields govern TTBR1, which is the
16	//!   kernel's own translation regime and must not be perturbed.
17	
18	use core::arch::asm;
19	
20	/// 4 KiB page size, in bytes.
21	pub const PAGE_SIZE: usize = 4096;
22	/// log2 of [`PAGE_SIZE`].
23	pub const PAGE_SHIFT: u32 = 12;
24	/// 512 entries per 4 KiB page table.
25	pub const PTES_PER_LEVEL: usize = 512;
26	
27	// ----- PTE bit positions ----------------------------------------------------
28	//
29	// ARMv8 stage-1 descriptor format (D5.3 in the ARM ARM). The bits we use:
30	
31	/// Entry is valid. Cleared = "translation fault on access".
32	pub const PTE_VALID: u64 = 1 << 0;
33	/// At L0/L1/L2: entry points at a next-level table (vs. a block). At L3:
34	/// must be 1 to indicate a page descriptor (block descriptors don't exist
35	/// at L3).
36	pub const PTE_TABLE: u64 = 1 << 1;
37	/// Inner Shareable shareability attribute. Mandatory for cacheable mappings
38	/// on multi-core systems; harmless on single-core QEMU.
39	pub const PTE_SH_INNER: u64 = 0b11 << 8;
40	/// Access Flag — must be set, or the first access generates a fault.
41	pub const PTE_AF: u64 = 1 << 10;
42	/// Privileged eXecute Never — kernel cannot fetch instructions from this
43	/// page. Always set on user mappings.
44	pub const PTE_PXN: u64 = 1 << 53;
45	/// Unprivileged eXecute Never — EL0 cannot fetch instructions. Set on
46	/// data/stack pages; cleared on code pages.
47	pub const PTE_UXN: u64 = 1 << 54;
48	
49	/// Access-permission field selecting EL1 RW + EL0 RW.
50	pub const PTE_AP_RW_EL0: u64 = 0b01 << 6;
51	/// Access-permission field selecting EL1 RO + EL0 RO.
52	pub const PTE_AP_RO_EL0: u64 = 0b11 << 6;
53	
54	/// Pack a MAIR attribute index into the descriptor's AttrIndx field.
55	pub const fn pte_attr_idx(idx: u64) -> u64 {
56	    (idx & 0b111) << 2
57	}
58	
59	/// MAIR_EL1 AttrIdx 0 — must encode Normal memory, Write-Back, RAWA. Limine
60	/// programs this; slice 2.3 only verifies.
61	pub const ATTR_IDX_NORMAL: u64 = 0;
62	/// Expected MAIR_EL1[7:0] for AttrIdx 0.
63	pub const MAIR_NORMAL_BYTE: u8 = 0xFF;
64	
65	// ----- PageTable -----------------------------------------------------------
66	
67	/// One 4 KiB page table — 512 × 8 B descriptors. The structure is its own
68	/// alignment guarantee so we can place it in static storage and hand a raw
69	/// physical address straight to TTBR0.
70	#[repr(C, align(4096))]
71	pub struct PageTable(pub [u64; PTES_PER_LEVEL]);
72	
73	impl PageTable {
74	    /// All-zero (= all-invalid) table for static initialization.
75	    pub const EMPTY: Self = Self([0; PTES_PER_LEVEL]);
76	
77	    #[inline]
78	    pub fn set(&mut self, idx: usize, desc: u64) {
79	        self.0[idx] = desc;
80	    }
81	}
82	
83	// ----- VA index helpers ----------------------------------------------------
84	
85	const fn pte_index(va: u64, level: u32) -> usize {
86	    // Each level consumes 9 VA bits (4 KiB granule). L0 indexes bits
87	    // [47:39], L1 [38:30], L2 [29:21], L3 [20:12].
88	    let shift = PAGE_SHIFT + 9 * (3 - level);
89	    ((va >> shift) & 0x1FF) as usize
90	}
91	
92	/// Build a table descriptor pointing at `next_table_pa`.
93	const fn make_table_desc(next_table_pa: u64) -> u64 {
94	    (next_table_pa & 0x0000_FFFF_FFFF_F000) | PTE_VALID | PTE_TABLE
95	}
96	
97	/// Build an L3 page descriptor for `pa` with the given attribute bits.
98	const fn make_page_desc(pa: u64, attrs: u64) -> u64 {
99	    (pa & 0x0000_FFFF_FFFF_F000) | PTE_VALID | PTE_TABLE | attrs
100	}
101	
102	// ----- Walker -------------------------------------------------------------
103	
104	/// Install a single 4 KiB mapping from `va` to `pa` with `attrs`.
105	///
106	/// `tables` must hold at least 4 page tables: `tables[0]` is the L0 root
107	/// (whose PA goes into TTBR0), and the walker writes the rest of the walk
108	/// into `tables[1..]` if they are not already linked. The simple slice-2.3
109	/// arrangement uses one fixed table at each level, so callers pre-allocate
110	/// `[L0, L1, L2, L3_for_va]`.
111	///
112	/// SAFETY: `tables[i]` must be live for the duration of the mapping; their
113	/// physical addresses must be reachable via [`super::limine::kernel_va_to_pa`].
114	pub unsafe fn map_4k(
115	    l0: &mut PageTable,
116	    l1: &mut PageTable,
117	    l2: &mut PageTable,
118	    l3: &mut PageTable,
119	    l1_pa: u64,
120	    l2_pa: u64,
121	    l3_pa: u64,
122	    va: u64,
123	    pa: u64,
124	    attrs: u64,
125	) {
126	    l0.set(pte_index(va, 0), make_table_desc(l1_pa));
127	    l1.set(pte_index(va, 1), make_table_desc(l2_pa));
128	    l2.set(pte_index(va, 2), make_table_desc(l3_pa));
129	    l3.set(pte_index(va, 3), make_page_desc(pa, attrs));
130	}
131	
132	// ----- TTBR0 / TCR / MAIR ---------------------------------------------------
133	
134	/// Verify Limine programmed AttrIdx 0 = Normal WB. We rely on this index
135	/// throughout slice 2.3.
136	pub fn assert_mair_normal_wb() {
137	    let mair: u64;
138	    // SAFETY: MAIR_EL1 is readable at EL1; no side effects.
139	    unsafe {
140	        asm!("mrs {0}, mair_el1", out(reg) mair, options(nomem, nostack, preserves_flags));
141	    }
142	    assert!(
143	        (mair & 0xFF) as u8 == MAIR_NORMAL_BYTE,
144	        "MAIR_EL1[7:0] = {:#04x}, expected Normal WB = {:#04x}",
145	        (mair & 0xFF) as u8,
146	        MAIR_NORMAL_BYTE,
147	    );
148	}
149	
150	/// Verify Limine programmed TCR_EL1's TTBR0-side walk structure the way our
151	/// page-table math assumes: 48-bit VA (T0SZ=16) so the walk has 4 levels,
152	/// and 4 KiB granule (TG0=0) so `pte_index` shifts by 12+9*… correctly.
153	/// IRGN0/ORGN0/SH0 are perf-only on single-core slice 2.3 and are reported
154	/// in the panic message but not enforced; `activate_user_ttbr0` leaves them
155	/// as Limine set them.
156	pub fn assert_tcr_el1_ttbr0_ready() {
157	    let tcr: u64;
158	    // SAFETY: TCR_EL1 is readable at EL1; no side effects.
159	    unsafe {
160	        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
161	    }
162	
163	    let t0sz = tcr & 0x3F;
164	    let tg0 = (tcr >> 14) & 0x3;
165	    let irgn0 = (tcr >> 8) & 0x3;
166	    let orgn0 = (tcr >> 10) & 0x3;
167	    let sh0 = (tcr >> 12) & 0x3;
168	
169	    assert!(
170	        t0sz == 16 && tg0 == 0b00,
171	        "TCR_EL1 = {tcr:#018x} (T0SZ={t0sz} TG0={tg0} IRGN0={irgn0} ORGN0={orgn0} SH0={sh0}); \
172	         slice 2.3 requires T0SZ=16 (48-bit VA, 4-level walk) and TG0=0 (4 KiB granule)",
173	    );
174	}
175	
176	/// Install `root_pa` as TTBR0_EL1 and ensure TTBR0 walks are enabled.
177	///
178	/// `assert_tcr_el1_ttbr0_ready` has already confirmed that Limine programmed
179	/// the structural TTBR0 fields (T0SZ=16, TG0=4 KiB) to match our walker, so
180	/// here we only need to clear EPD0 if set. We deliberately read-modify-write
181	/// just bit 7 — touching any other TCR field risks perturbing TTBR1, which
182	/// Limine owns and whose translations the kernel is actively using.
183	///
184	/// SAFETY: must be called with interrupts masked. `root_pa` must point at a
185	/// valid L0 page table.
186	pub unsafe fn activate_user_ttbr0(root_pa: u64) {
187	    const TCR_EPD0: u64 = 1 << 7;
188	
189	    // SAFETY: TTBR0_EL1, TCR_EL1, and TLB-maintenance ops are EL1-only and
190	    // touch no normal memory. Bit 7 (EPD0) is the only TCR field we
191	    // perturb; the rest stays as Limine left it.
192	    unsafe {
193	        let tcr: u64;
194	        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
195	        let new_tcr = tcr & !TCR_EPD0;
196	
197	        asm!(
198	            "msr ttbr0_el1, {root}",
199	            "msr tcr_el1, {tcr}",
200	            "isb",
201	            "tlbi vmalle1",
202	            "dsb ish",
203	            "isb",
204	            root = in(reg) root_pa,
205	            tcr = in(reg) new_tcr,
206	            options(nomem, nostack, preserves_flags),
207	        );
208	    }
209	}
210	
211	/// Make instruction memory coherent with a recent data write at `va..va+len`.
212	///
213	/// AArch64 caches are PIPT for data but VIPT-flavored for instructions; after
214	/// writing into a code page we must clean the data side to PoU, then
215	/// invalidate the i-cache. Sequence is straight out of the ARM ARM §B2.4
216	/// example.
217	///
218	/// SAFETY: `va..va+len` must be a valid mapped range readable at EL1.
219	pub unsafe fn flush_icache_range(va: u64, len: usize) {
220	    // CTR_EL0.DminLine (bits 19:16) = log2 of the minimum D-cache line
221	    // size in words; multiply by the 4 B word size to get bytes. QEMU virt
222	    // reports 64 here; Apple Silicon reports 128.
223	    let ctr: u64;
224	    // SAFETY: CTR_EL0 is readable at EL1; no side effects.
225	    unsafe {
226	        asm!("mrs {0}, ctr_el0", out(reg) ctr, options(nomem, nostack, preserves_flags));
227	    }
228	    let line_bytes = 4_u64 << ((ctr >> 16) & 0xF);
