/// Look for the first pending notification matching `src_e` (or any, if
/// `src_e == ANY`) in `caller`'s `notify_pending` bitmap. Returns the
/// sender's endpoint and clears the bit on success.
fn take_pending_notification(
    proc_table: &[Proc; N_PROC_SLOTS],
    priv_table: &mut [Priv; NR_SYS_PROCS],
    caller_idx: usize,
    src_e: Endpoint,
) -> Option<Endpoint> {
    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
        return None;
    };
    let pending = &mut priv_table[caller_priv_id.as_usize()].notify_pending;

    for chunk_idx in 0..pending.len() {
        let mut chunk = pending[chunk_idx];
        while chunk != 0 {
            let bit = chunk.trailing_zeros() as usize;
            let sender_priv_idx = chunk_idx * 32 + bit;
            // Look up the sender's process.
            if sender_priv_idx < NR_SYS_PROCS {
                // Snapshot sender info without mutably borrowing priv_table.
                // We have an existing &mut borrow to the caller's slot; we
                // only need a read of the sender's slot, which the compiler
                // can prove disjoint by reading from a separate split.
                if let Some(sender_nr) = priv_proc_nr(priv_table, sender_priv_idx) {
                    let sender_idx = proc_index(sender_nr)?;
                    let sender_e = proc_table[sender_idx].endpoint;
