                        // Clear bit and return.
                        priv_table[caller_priv_id.as_usize()].notify_pending[chunk_idx] &=
                            !(1u32 << bit);
                        return Some(sender_e);
                    }
                }
            }
            chunk &= chunk - 1; // pop lowest set bit and try next
        }
    }
    None
}

