9	use core::fmt::{self, Write};
10	use core::sync::atomic::Ordering;
11	
12	use arrayvec::ArrayString;
13	
14	use super::flags::{
15	    BILLABLE, PREEMPTIBLE, ROOT_SYS_PROC, RTS_BOOTINHIBIT, RTS_NO_ENDPOINT, RTS_NO_PRIV,
16	    RTS_PAGEFAULT, RTS_PREEMPTED, RTS_PROC_STOP, RTS_RECEIVING, RTS_SENDING, RTS_SIGNALED,
17	    RTS_SIG_PENDING, RTS_SLOT_FREE, RTS_VMINHIBIT, SYS_PROC, VM_SYS_PROC,
18	};
19	use super::priv_struct::Priv;
20	use super::proc_struct::Proc;
21	use super::table::{n_image_slots, n_proc_slots, priv_table_ref, proc_table_ref};
22	
23	const NAME_WIDTH: usize = 16;
24	const RTS_WIDTH: usize = 24;
25	const PRIV_FLAGS_WIDTH: usize = 24;
26	
27	/// Dump the populated process + privilege tables to `out`.
28	///
29	/// SAFETY-adjacent: takes shared references to the static tables; callers
30	/// must ensure no exclusive borrow is live for the call. Slice 2.2 invokes
31	/// this once after `proc::init()` returns and never re-enters init, so the
32	/// requirement is trivially met.
33	pub fn dump_tables<W: Write>(out: &mut W) -> fmt::Result {
34	    // SAFETY: single-threaded boot context; `proc::init()` has returned, so
35	    // no `&mut` reference into PROC_TABLE / PRIV_TABLE is live.
36	    let procs = unsafe { proc_table_ref() };
37	    let privs = unsafe { priv_table_ref() };
38	
39	    let active = procs.iter().filter(|p| !is_free(p)).count();
40	    writeln!(
41	        out,
42	        "Process table ({} slots, {} active):",
43	        n_proc_slots(),
44	        active,
45	    )?;
46	    writeln!(
47	        out,
48	        "   nr  endpoint    {:<NAME_WIDTH$}  priv  {:<RTS_WIDTH$}  prio  q_ms",
49	        "name", "rts",
50	    )?;
51	    for p in procs.iter() {
52	        if is_free(p) {
53	            continue;
54	        }
55	        dump_proc(out, p)?;
56	    }
57	
58	    let used = privs.iter().filter(|pr| pr.proc_nr.is_some()).count();
59	    writeln!(out)?;
60	    writeln!(
61	        out,
62	        "Privilege table ({} used / {} total, image = {}):",
63	        used,
64	        privs.len(),
65	        n_image_slots(),
66	    )?;
67	    writeln!(
68	        out,
69	        "   id  proc-nr  {:<PRIV_FLAGS_WIDTH$}  trap    ipc_to                  k_call",
70	        "flags",
71	    )?;
72	    for pr in privs.iter() {
73	        if pr.proc_nr.is_none() {
74	            continue;
75	        }
76	        dump_priv(out, pr)?;
77	    }
78	
79	    Ok(())
80	}
81	
82	fn is_free(p: &Proc) -> bool {
83	    p.rts_flags.load(Ordering::Relaxed) & RTS_SLOT_FREE != 0
84	}
85	
86	fn dump_proc<W: Write>(out: &mut W, p: &Proc) -> fmt::Result {
87	    writeln!(
88	        out,
89	        "  {:>3}  {:#010x}  {:<NAME_WIDTH$}  {:>4}  {:<RTS_WIDTH$}  {:>4}  {:>4}",
90	        p.nr.get(),
91	        p.endpoint as u32,
92	        NameDecoder(&p.name),
93	        PrivIdDisplay(p.priv_id),
94	        RtsDecoder(p.rts_flags.load(Ordering::Relaxed)),
95	        p.priority,
96	        p.quantum_ms,
97	    )
98	}
99	
100	fn dump_priv<W: Write>(out: &mut W, pr: &Priv) -> fmt::Result {
101	    let proc_nr = pr.proc_nr.map(|n| n.get()).unwrap_or(i32::MIN);
102	    writeln!(
103	        out,
104	        "  {:>3}  {:>7}  {:<PRIV_FLAGS_WIDTH$}  {:#06x}  {:#010x} {:#010x}  {:#010x}",
105	        pr.id.get(),
106	        proc_nr,
107	        PrivFlagDecoder(pr.flags),
108	        pr.trap_mask,
109	        pr.ipc_to[0],
110	        pr.ipc_to[1],
111	        pr.k_call_mask[0],
112	    )
113	}
