115	// ---------------------------------------------------------------------------
116	// Width-aware Display wrappers.
117	//
118	// `f.pad(s)` is the supported path for honouring `{:<width$}` from a custom
119	// Display impl: render into a fixed-size stack buffer, then hand the buffer
120	// to the formatter. ArrayString here keeps the dump zero-alloc.
121	// ---------------------------------------------------------------------------
122	
123	const RENDER_BUF: usize = 96;
124	
125	fn render_padded<F>(f: &mut fmt::Formatter<'_>, render: F) -> fmt::Result
126	where
127	    F: FnOnce(&mut ArrayString<RENDER_BUF>) -> fmt::Result,
128	{
129	    let mut buf: ArrayString<RENDER_BUF> = ArrayString::new();
130	    // Ignore overflow — the buffer is sized to fit every label we emit; if a
131	    // future label trips this, the truncated output still lands but signals
132	    // we need a bigger buffer.
133	    let _ = render(&mut buf);
134	    f.pad(buf.as_str())
135	}
136	
137	struct NameDecoder<'a>(&'a [u8]);
138	
139	impl<'a> fmt::Display for NameDecoder<'a> {
140	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
141	        render_padded(f, |buf| {
142	            for &b in self.0 {
143	                if b == 0 {
144	                    break;
145	                }
146	                let c = if b.is_ascii() && !b.is_ascii_control() {
147	                    b as char
148	                } else {
149	                    '?'
150	                };
151	                let _ = buf.try_push(c);
152	            }
153	            Ok(())
154	        })
155	    }
156	}
157	
158	struct PrivIdDisplay(Option<minix4_kernel_shared::PrivId>);
159	
160	impl fmt::Display for PrivIdDisplay {
161	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
162	        render_padded(f, |buf| match self.0 {
163	            Some(id) => write!(buf, "{}", id.get()),
164	            None => buf.write_str("-"),
165	        })
166	    }
167	}
168	
169	struct RtsDecoder(u32);
170	
171	impl fmt::Display for RtsDecoder {
172	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
173	        let v = self.0;
174	        render_padded(f, |buf| {
175	            if v == 0 {
176	                return buf.write_str("RUN");
177	            }
178	            let mut first = true;
179	            let pairs: [(u32, &str); 12] = [
180	                (RTS_PROC_STOP, "STOP"),
181	                (RTS_SENDING, "SEND"),
182	                (RTS_RECEIVING, "RECV"),
183	                (RTS_SIGNALED, "SIGD"),
184	                (RTS_SIG_PENDING, "SIGP"),
185	                (RTS_NO_PRIV, "NOPRIV"),
186	                (RTS_NO_ENDPOINT, "NOEPT"),
187	                (RTS_VMINHIBIT, "VMINH"),
188	                (RTS_PAGEFAULT, "PGFLT"),
189	                (RTS_PREEMPTED, "PREEMPT"),
190	                (RTS_BOOTINHIBIT, "BOOTINH"),
191	                (RTS_SLOT_FREE, "FREE"),
192	            ];
193	            for (bit, name) in pairs {
194	                if v & bit != 0 {
195	                    if !first {
196	                        buf.write_char('|')?;
197	                    }
198	                    buf.write_str(name)?;
199	                    first = false;
200	                }
201	            }
202	            Ok(())
203	        })
204	    }
205	}
206	
207	struct PrivFlagDecoder(u16);
208	
209	impl fmt::Display for PrivFlagDecoder {
210	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
211	        let v = self.0;
212	        render_padded(f, |buf| {
213	            if v == 0 {
214	                return buf.write_str("-");
215	            }
216	            let mut first = true;
217	            let pairs: [(u16, &str); 5] = [
218	                (SYS_PROC, "SYS"),
219	                (PREEMPTIBLE, "PREEMPT"),
220	                (BILLABLE, "BILL"),
221	                (ROOT_SYS_PROC, "ROOT"),
222	                (VM_SYS_PROC, "VMSYS"),
223	            ];
224	            for (bit, name) in pairs {
225	                if v & bit != 0 {
226	                    if !first {
227	                        buf.write_char('|')?;
228	                    }
229	                    buf.write_str(name)?;
230	                    first = false;
231	                }
232	            }
